from agent import *from models.products import *	def run(context, session):	    session.queue(Request("https://www.220volt.hu/Teszt"), process_revlist, {})	def process_revlist(data, context, session):	    for rev in data.xpath("//div[@class='blog-item__title mb-3 font-weight-bold']/a"):	        title = rev.xpath("text()").string()	        url = rev.xpath("@href").string()	        if url:	            session.queue(Request(url), process_review, dict(title=title, url=url))	def process_review(data, context, session):	    product = Product()	    product.name = context['title']	    product.url = context['url']	    product.ssid = product.url.split('/')[-1]	    product.category = 'Photography'	    content = data.xpath("//div[@class='blog-details']").first()	    if not content:	        return	    review = Review()	    review.type = 'pro'	    review.title = context['title']	    review.url = product.url	    review.ssid = product.ssid	    review.date = content.xpath("//span[@class='blog-date']/text()").string()	    author = content.xpath("//p/a[@rel='nofollow noopener']").last()	    if author:	        name = author.xpath("text()").string()	        url = author.xpath("@href").string()	        if name and url:	            review.authors.append(Person(name=name, ssid=url, profile_url=url))	    excerpt = content.xpath(".//p//text()").string(multiple=True)	    if not excerpt:	        return	    summary = content.xpath("div[@class='blog-details__intro font-s font-md-m clearfix mb-5']//text()").string(multiple=True)	    if summary:	        review.properties.append(ReviewProperty(type='summary', value=summary))	        excerpt = excerpt.replace(summary, '')	    pros = content.xpath("//h3[contains(.,'pozitívumai')]/following-sibling::p/text()")	    if not pros:	        pros = content.xpath("//h3[contains(.,'pozitívumai')]/following-sibling::ul/li/text()")	    for pro in pros:	        text = pro.xpath("self::text()").string(multiple=True)	        excerpt = excerpt.replace(text, '')	        if text:	            text = text.replace('+ ', '').replace('- ', '')	            review.properties.append(ReviewProperty(type='pros', value=text))	    cons = content.xpath("//h3[contains(.,'negatívumai')]/following-sibling::p/text()")	    if not cons:	        cons = content.xpath("//h3[contains(.,'negatívumai')]/following-sibling::ul/li/text()")	    for con in cons:	        text = con.xpath("self::text()").string(multiple=True)	        excerpt = excerpt.replace(text, '')	        if text:	            text = text.replace('+ ', '').replace('- ', '')	            review.properties.append(ReviewProperty(type='cons', value=text))	    conclusion = content.xpath("//h3[contains(.,'röviden')]/following-sibling::p/text()").string(multiple=True)	    if conclusion:	        review.properties.append(ReviewProperty(type='conclusion', value=conclusion))	        excerpt = excerpt.replace(conclusion, '')	    excerpt = excerpt.split('Írta')[0].replace('Letöltöm a nyers fotókat!', '')	    recommended = content.xpath("//p[contains(.,'számodra:')]/text()").string()	    if recommended:	        excerpt = excerpt.replace(recommended, '')	    excerpt = excerpt.strip()	    if excerpt:	        review.properties.append(ReviewProperty(type='excerpt', value=excerpt))	        product.reviews.append(review)	        session.emit(product)	